CREATE OR REPLACE FUNCTION public.destock_order(p_order_id uuid, p_tenant_id uuid, p_created_by uuid DEFAULT NULL)
RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$
DECLARE v_count INT:=0; v_item RECORD; v_recipe RECORD; v_new_stock NUMERIC(10,3); v_required NUMERIC(10,3);
BEGIN
  PERFORM pg_advisory_xact_lock(hashtext('destock_order:' || p_order_id::text));
  IF EXISTS (SELECT 1 FROM public.stock_movements WHERE reference_id=p_order_id AND movement_type='order_destock')
    THEN RETURN 0; END IF;
  FOR v_item IN SELECT oi.menu_item_id, oi.quantity FROM public.order_items oi
    JOIN public.orders o ON o.id=oi.order_id WHERE oi.order_id=p_order_id AND o.tenant_id=p_tenant_id LOOP
