      WHERE r.menu_item_id=v_item.menu_item_id AND r.tenant_id=p_tenant_id LOOP
      v_required := v_recipe.quantity_needed * v_item.quantity;
      UPDATE public.ingredients SET current_stock=current_stock - v_required
        WHERE id=v_recipe.ingredient_id AND tenant_id=p_tenant_id AND current_stock >= v_required
        RETURNING current_stock INTO v_new_stock;
      IF NOT FOUND THEN RAISE EXCEPTION 'INSUFFICIENT_STOCK'; END IF;
      INSERT INTO public.stock_movements (tenant_id,ingredient_id,movement_type,quantity,reference_id,created_by)
        VALUES (p_tenant_id,v_recipe.ingredient_id,'order_destock',-v_required,p_order_id,p_created_by);
      IF v_new_stock <= 0 THEN
        UPDATE public.menu_items SET is_available=false WHERE id IN
          (SELECT r2.menu_item_id FROM public.recipes r2 WHERE r2.ingredient_id=v_recipe.ingredient_id AND r2.tenant_id=p_tenant_id)
          AND tenant_id=p_tenant_id AND is_available=true;
      END IF;
      v_count := v_count + 1;
