-- 4. restock_order + p_created_by
DROP FUNCTION IF EXISTS public.restock_order(uuid, uuid);
CREATE OR REPLACE FUNCTION public.restock_order(p_order_id uuid, p_tenant_id uuid, p_created_by uuid DEFAULT NULL)
RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$
DECLARE v_count INT:=0; v_mov RECORD; v_new_stock NUMERIC(10,3);
BEGIN
  FOR v_mov IN SELECT sm.ingredient_id, SUM(sm.quantity) AS net_destocked FROM public.stock_movements sm
    WHERE sm.reference_id=p_order_id AND sm.tenant_id=p_tenant_id AND sm.movement_type='order_destock'
    GROUP BY sm.ingredient_id HAVING SUM(sm.quantity) < 0 LOOP
    IF EXISTS (SELECT 1 FROM public.stock_movements r WHERE r.reference_id=p_order_id AND r.tenant_id=p_tenant_id
      AND r.movement_type='order_restock' AND r.ingredient_id=v_mov.ingredient_id) THEN CONTINUE; END IF;
    UPDATE public.ingredients SET current_stock=current_stock + ABS(v_mov.net_destocked)
      WHERE id=v_mov.ingredient_id AND tenant_id=p_tenant_id RETURNING current_stock INTO v_new_stock;
    IF NOT FOUND THEN CONTINUE; END IF;
    INSERT INTO public.stock_movements (tenant_id,ingredient_id,movement_type,quantity,reference_id,notes,created_by)
      VALUES (p_tenant_id,v_mov.ingredient_id,'order_restock',ABS(v_mov.net_destocked),p_order_id,'Annulation / remboursement commande',p_created_by);
    IF v_new_stock > 0 THEN
      UPDATE public.menu_items SET is_available=true WHERE id IN
        (SELECT r2.menu_item_id FROM public.recipes r2 WHERE r2.ingredient_id=v_mov.ingredient_id AND r2.tenant_id=p_tenant_id)
        AND tenant_id=p_tenant_id AND is_available=false;
    END IF;
    v_count := v_count + 1;
  END LOOP;
  RETURN v_count;
END; $$;
REVOKE ALL ON FUNCTION public.restock_order(uuid,uuid,uuid) FROM PUBLIC, anon, authenticated;
GRANT EXECUTE ON FUNCTION public.restock_order(uuid,uuid,uuid) TO service_role;

-- 5. set_opening_stock + p_created_by, enregistre le DELTA (new-before) pour ledger reconstruible
DROP FUNCTION IF EXISTS public.set_opening_stock(uuid, uuid, numeric);
CREATE OR REPLACE FUNCTION public.set_opening_stock(p_tenant_id uuid, p_ingredient_id uuid, p_quantity numeric, p_created_by uuid DEFAULT NULL)
RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$
DECLARE v_before NUMERIC(10,3);
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  SELECT current_stock INTO v_before FROM public.ingredients WHERE id=p_ingredient_id AND tenant_id=p_tenant_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'INGREDIENT_NOT_FOUND' USING ERRCODE='P0002'; END IF;
  UPDATE public.ingredients SET current_stock=p_quantity, updated_at=now() WHERE id=p_ingredient_id AND tenant_id=p_tenant_id;
  INSERT INTO public.stock_movements (tenant_id,ingredient_id,movement_type,quantity,notes,created_by)
    VALUES (p_tenant_id,p_ingredient_id,'opening',p_quantity - v_before,'Stock d''ouverture',p_created_by);
END; $$;
REVOKE ALL ON FUNCTION public.set_opening_stock(uuid,uuid,numeric,uuid) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.set_opening_stock(uuid,uuid,numeric,uuid) TO authenticated, service_role;

-- 6. adjust_ingredient_stock_tx + p_reason_code + type 'loss'
DROP FUNCTION IF EXISTS public.adjust_ingredient_stock_tx(uuid,uuid,numeric,text,text,uuid,uuid);
CREATE OR REPLACE FUNCTION public.adjust_ingredient_stock_tx(p_tenant_id uuid, p_ingredient_id uuid, p_delta numeric,
  p_movement_type text, p_notes text DEFAULT NULL, p_created_by uuid DEFAULT NULL, p_supplier_id uuid DEFAULT NULL, p_reason_code text DEFAULT NULL)
RETURNS numeric LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$
DECLARE v_before NUMERIC(10,3); v_after NUMERIC(10,3);
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  IF p_movement_type NOT IN ('manual_add','manual_remove','adjustment','opening','loss') THEN
    RAISE EXCEPTION 'INVALID_MOVEMENT_TYPE: %', p_movement_type USING ERRCODE='22023'; END IF;
  IF p_supplier_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM public.suppliers s WHERE s.id=p_supplier_id AND s.tenant_id=p_tenant_id)
    THEN RAISE EXCEPTION 'INVALID_SUPPLIER' USING ERRCODE='22023'; END IF;
  SELECT current_stock INTO v_before FROM public.ingredients WHERE id=p_ingredient_id AND tenant_id=p_tenant_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'INGREDIENT_NOT_FOUND' USING ERRCODE='P0002'; END IF;
  v_after := GREATEST(0, v_before + p_delta);
  UPDATE public.ingredients SET current_stock=v_after, updated_at=now() WHERE id=p_ingredient_id AND tenant_id=p_tenant_id;
  INSERT INTO public.stock_movements (tenant_id,ingredient_id,movement_type,quantity,notes,created_by,supplier_id,reason_code)
    VALUES (p_tenant_id,p_ingredient_id,p_movement_type,v_after - v_before,p_notes,p_created_by,p_supplier_id,p_reason_code);
  RETURN v_after;
END; $$;
REVOKE ALL ON FUNCTION public.adjust_ingredient_stock_tx(uuid,uuid,numeric,text,text,uuid,uuid,text) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.adjust_ingredient_stock_tx(uuid,uuid,numeric,text,text,uuid,uuid,text) TO authenticated, service_role;

-- 7. record_physical_count_tx : comptage physique (SET-to-count, enregistre le delta)
CREATE OR REPLACE FUNCTION public.record_physical_count_tx(p_tenant_id uuid, p_ingredient_id uuid, p_counted numeric,
  p_notes text DEFAULT NULL, p_created_by uuid DEFAULT NULL, p_reason_code text DEFAULT NULL)
RETURNS numeric LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$
DECLARE v_before NUMERIC(10,3); v_after NUMERIC(10,3);
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  IF p_counted IS NULL OR p_counted < 0 THEN RAISE EXCEPTION 'INVALID_QUANTITY' USING ERRCODE='22023'; END IF;
  SELECT current_stock INTO v_before FROM public.ingredients WHERE id=p_ingredient_id AND tenant_id=p_tenant_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'INGREDIENT_NOT_FOUND' USING ERRCODE='P0002'; END IF;
  v_after := p_counted;
  UPDATE public.ingredients SET current_stock=v_after, updated_at=now() WHERE id=p_ingredient_id AND tenant_id=p_tenant_id;
  INSERT INTO public.stock_movements (tenant_id,ingredient_id,movement_type,quantity,notes,created_by,reason_code)
    VALUES (p_tenant_id,p_ingredient_id,'physical_count',v_after - v_before,p_notes,p_created_by,COALESCE(p_reason_code,'recount'));
  RETURN v_after;
END; $$;
REVOKE ALL ON FUNCTION public.record_physical_count_tx(uuid,uuid,numeric,text,uuid,text) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.record_physical_count_tx(uuid,uuid,numeric,text,uuid,text) TO authenticated, service_role;

-- 8. verify_stock_ledger : rapport de derive lecture seule (cache vs SUM(deltas))
CREATE OR REPLACE FUNCTION public.verify_stock_ledger(p_tenant_id uuid)
RETURNS TABLE(ingredient_id uuid, name text, current_stock numeric, ledger_sum numeric, drift numeric)
LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  RETURN QUERY
  SELECT i.id, i.name, i.current_stock,
    COALESCE(SUM(sm.quantity),0)::numeric(10,3),
    (i.current_stock - COALESCE(SUM(sm.quantity),0))::numeric(10,3)
  FROM public.ingredients i
  LEFT JOIN public.stock_movements sm ON sm.ingredient_id=i.id AND sm.tenant_id=p_tenant_id
  WHERE i.tenant_id=p_tenant_id AND i.is_active=true
  GROUP BY i.id, i.name, i.current_stock
  HAVING (i.current_stock - COALESCE(SUM(sm.quantity),0)) <> 0
  ORDER BY i.name;
END; $$;
REVOKE ALL ON FUNCTION public.verify_stock_ledger(uuid) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.verify_stock_ledger(uuid) TO authenticated, service_role;

-- 9. reconcile_stock_ledger : reparation (insere adjustment de la derive, reason 'reconcile')
CREATE OR REPLACE FUNCTION public.reconcile_stock_ledger(p_tenant_id uuid, p_created_by uuid DEFAULT NULL)
RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$
DECLARE v_row RECORD; v_n INT:=0;
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  FOR v_row IN SELECT i.id, (i.current_stock - COALESCE(SUM(sm.quantity),0)) AS drift
    FROM public.ingredients i LEFT JOIN public.stock_movements sm ON sm.ingredient_id=i.id AND sm.tenant_id=p_tenant_id
    WHERE i.tenant_id=p_tenant_id AND i.is_active=true GROUP BY i.id, i.current_stock
    HAVING (i.current_stock - COALESCE(SUM(sm.quantity),0)) <> 0 LOOP
    INSERT INTO public.stock_movements (tenant_id,ingredient_id,movement_type,quantity,notes,created_by,reason_code)
      VALUES (p_tenant_id,v_row.id,'adjustment',v_row.drift,'Reconciliation ledger',p_created_by,'reconcile');
    v_n := v_n + 1;
  END LOOP;
  RETURN v_n;
END; $$;
REVOKE ALL ON FUNCTION public.reconcile_stock_ledger(uuid,uuid) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.reconcile_stock_ledger(uuid,uuid) TO authenticated, service_role;

COMMIT;

-- 20260701040000_physical_stock_count.sql  (ADDITIVE ONLY)
-- Depends on chantier 'ledger'. If 'ledger' already added 'physical_count' to the
-- movement_type CHECK, the ALTER below simply re-states the full allowed list.

-- 1. movement_type: allow 'physical_count' (additive re-statement of the CHECK)
ALTER TABLE public.stock_movements
  DROP CONSTRAINT IF EXISTS stock_movements_movement_type_check;
ALTER TABLE public.stock_movements
  ADD CONSTRAINT stock_movements_movement_type_check
  CHECK (movement_type IN (
    'order_destock','order_restock','manual_add','manual_remove',
    'adjustment','opening','physical_count'
  ));

-- 2. stock_counts (session)
CREATE TABLE IF NOT EXISTS public.stock_counts (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE,
  reference TEXT,
  status TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open','committed','cancelled')),
  created_by UUID,
  committed_by UUID,
  committed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX idx_stock_counts_tenant ON public.stock_counts(tenant_id);
CREATE INDEX idx_stock_counts_tenant_status ON public.stock_counts(tenant_id, status);
-- at most one open session per tenant (avoids overlapping snapshots)
CREATE UNIQUE INDEX uniq_stock_counts_one_open
  ON public.stock_counts(tenant_id) WHERE status = 'open';

-- 3. stock_count_lines
CREATE TABLE IF NOT EXISTS public.stock_count_lines (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE,
  count_id UUID NOT NULL REFERENCES public.stock_counts(id) ON DELETE CASCADE,
  ingredient_id UUID NOT NULL REFERENCES public.ingredients(id) ON DELETE CASCADE,
  theoretical_qty NUMERIC(10,3) NOT NULL DEFAULT 0,
  counted_qty NUMERIC(10,3),
  variance NUMERIC(10,3) GENERATED ALWAYS AS (counted_qty - theoretical_qty) STORED,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  UNIQUE(count_id, ingredient_id)
);
CREATE INDEX idx_stock_count_lines_tenant ON public.stock_count_lines(tenant_id);
CREATE INDEX idx_stock_count_lines_count ON public.stock_count_lines(count_id);
CREATE INDEX idx_stock_count_lines_ingredient ON public.stock_count_lines(ingredient_id);

-- reuse the existing updated_at trigger fn pattern
CREATE TRIGGER trigger_stock_counts_updated_at
  BEFORE UPDATE ON public.stock_counts
  FOR EACH ROW EXECUTE FUNCTION public.update_ingredients_updated_at();

-- 4. RLS (tenant-scoped via admin_users, same shape as inventory_engine)
ALTER TABLE public.stock_counts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.stock_count_lines ENABLE ROW LEVEL SECURITY;
CREATE POLICY stock_counts_select ON public.stock_counts FOR SELECT
