-- 5. record_loss_tx: atomic decrement + reconcilable ledger movement.
--    Mirrors adjust_ingredient_stock_tx (records ACTUAL applied delta after the
--    >=0 clamp so sum(movements)=current_stock) and mirrors destock_order's
--    auto-unavailable flip when an ingredient hits 0.
CREATE OR REPLACE FUNCTION public.record_loss_tx(
  p_tenant_id uuid,
  p_ingredient_id uuid,
  p_quantity numeric,
  p_reason_code public.stock_loss_reason,
  p_notes text DEFAULT NULL,
  p_created_by uuid DEFAULT NULL
)
RETURNS numeric
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
DECLARE
  v_before NUMERIC(10,3);
  v_after  NUMERIC(10,3);
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);

  IF p_quantity IS NULL OR p_quantity <= 0 THEN
    RAISE EXCEPTION 'INVALID_QUANTITY' USING ERRCODE = '22023';
  END IF;
  IF p_reason_code IS NULL THEN
    RAISE EXCEPTION 'INVALID_REASON' USING ERRCODE = '22023';
  END IF;

  SELECT current_stock INTO v_before
  FROM public.ingredients
  WHERE id = p_ingredient_id AND tenant_id = p_tenant_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'INGREDIENT_NOT_FOUND' USING ERRCODE = 'P0002';
  END IF;

  v_after := GREATEST(0, v_before - p_quantity);

  UPDATE public.ingredients
  SET current_stock = v_after, updated_at = now()
  WHERE id = p_ingredient_id AND tenant_id = p_tenant_id;

  INSERT INTO public.stock_movements
    (tenant_id, ingredient_id, movement_type, quantity, reason_code, notes, created_by)
  VALUES
    (p_tenant_id, p_ingredient_id, 'loss', v_after - v_before, p_reason_code, p_notes, p_created_by);

  -- Bring dependent menu items down if the ingredient is now depleted.
  IF v_after <= 0 THEN
    UPDATE public.menu_items
    SET is_available = false
    WHERE id IN (
      SELECT r.menu_item_id FROM public.recipes r
      WHERE r.ingredient_id = p_ingredient_id AND r.tenant_id = p_tenant_id
    )
    AND tenant_id = p_tenant_id AND is_available = true;
  END IF;

  RETURN v_after;
END;
$function$;

REVOKE ALL ON FUNCTION public.record_loss_tx(uuid, uuid, numeric, public.stock_loss_reason, text, uuid)
  FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.record_loss_tx(uuid, uuid, numeric, public.stock_loss_reason, text, uuid)
  TO authenticated, service_role;

-- 6. get_losses_by_reason: report aggregation (count / qty / valued cost).
--    cost_per_unit is the legacy NUMERIC(10,2) column on ingredients.
CREATE OR REPLACE FUNCTION public.get_losses_by_reason(
  p_tenant_id uuid,
  p_start timestamptz DEFAULT NULL,
  p_end   timestamptz DEFAULT NULL
)
RETURNS TABLE (
  reason_code public.stock_loss_reason,
  nb_movements bigint,
  total_qty numeric,
  total_cost_value numeric
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  RETURN QUERY
  SELECT
    sm.reason_code,
    COUNT(*)::bigint,
    COALESCE(SUM(ABS(sm.quantity)), 0),
    COALESCE(SUM(ABS(sm.quantity) * i.cost_per_unit), 0)
  FROM public.stock_movements sm
  JOIN public.ingredients i
    ON i.id = sm.ingredient_id AND i.tenant_id = sm.tenant_id
  WHERE sm.tenant_id = p_tenant_id
    AND sm.movement_type = 'loss'
    AND (p_start IS NULL OR sm.created_at >= p_start)
    AND (p_end   IS NULL OR sm.created_at <= p_end)
  GROUP BY sm.reason_code
  ORDER BY 4 DESC;
END;
$function$;

REVOKE ALL ON FUNCTION public.get_losses_by_reason(uuid, timestamptz, timestamptz)
  FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.get_losses_by_reason(uuid, timestamptz, timestamptz)
  TO authenticated, service_role;

-- supabase/migrations/20260701120000_recipe_import_tx.sql
-- ADDITIVE ONLY. Adds a lookup index + one SECURITY DEFINER RPC for atomic
-- recipe (fiche technique) Excel import with get-or-create of missing ingredients.
-- No new tables/columns, no destructive change. Safe to apply before code is wired
-- (nothing calls the RPC until recipe-import.service.ts ships).
-- Rollback: DROP FUNCTION public.import_recipes_tx(uuid, jsonb);
--           DROP INDEX IF EXISTS public.idx_ingredients_tenant_lower_name;

CREATE INDEX IF NOT EXISTS idx_ingredients_tenant_lower_name
  ON public.ingredients (tenant_id, lower(name));

CREATE OR REPLACE FUNCTION public.import_recipes_tx(
  p_tenant_id uuid,
  p_rows jsonb
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $function$
DECLARE
  v_row jsonb;
  v_menu_item_id uuid;
  v_ing_name text;
  v_ing_unit text;
  v_qty numeric;
  v_notes text;
  v_ingredient_id uuid;
  v_existed boolean;
  v_recipes_created int := 0;
  v_recipes_updated int := 0;
  v_ingredients_created int := 0;
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);

  FOR v_row IN SELECT * FROM jsonb_array_elements(COALESCE(p_rows, '[]'::jsonb))
  LOOP
    v_menu_item_id := (v_row->>'menu_item_id')::uuid;
    v_ing_name     := btrim(v_row->>'ingredient_name');
    v_ing_unit     := v_row->>'unit';
    v_qty          := (v_row->>'quantity_needed')::numeric;
    v_notes        := NULLIF(btrim(COALESCE(v_row->>'notes','')), '');

    -- Defensive re-validation (service pre-validates + pre-resolves menu_item_id).
    IF v_qty IS NULL OR v_qty <= 0 THEN
      RAISE EXCEPTION 'INVALID_QUANTITY' USING ERRCODE = '22023';
    END IF;
    IF v_ing_unit NOT IN ('kg','L','piece_unit','cl','g','bouteille') THEN
      -- NB: real enum value for piece uses the accented form already in the
      -- CHECK constraint from 20260212000001; keep it identical there.
      RAISE EXCEPTION 'INVALID_UNIT: %', v_ing_unit USING ERRCODE = '22023';
    END IF;
    IF NOT EXISTS (SELECT 1 FROM public.menu_items mi
                   WHERE mi.id = v_menu_item_id AND mi.tenant_id = p_tenant_id) THEN
      RAISE EXCEPTION 'MENU_ITEM_NOT_FOUND' USING ERRCODE = 'P0002';
    END IF;

    -- get-or-create ingredient (case-insensitive per tenant, prefer active)
    SELECT id INTO v_ingredient_id
    FROM public.ingredients
    WHERE tenant_id = p_tenant_id AND lower(name) = lower(v_ing_name)
    ORDER BY is_active DESC, created_at
    LIMIT 1;

    IF v_ingredient_id IS NULL THEN
      INSERT INTO public.ingredients (tenant_id, name, unit)
      VALUES (p_tenant_id, v_ing_name, v_ing_unit)
      RETURNING id INTO v_ingredient_id;
      v_ingredients_created := v_ingredients_created + 1;
    END IF;

    SELECT EXISTS (SELECT 1 FROM public.recipes
                   WHERE menu_item_id = v_menu_item_id
                     AND ingredient_id = v_ingredient_id) INTO v_existed;

    -- merge-upsert (recipes.UNIQUE(menu_item_id, ingredient_id))
    INSERT INTO public.recipes (tenant_id, menu_item_id, ingredient_id, quantity_needed, notes)
    VALUES (p_tenant_id, v_menu_item_id, v_ingredient_id, v_qty, v_notes)
    ON CONFLICT (menu_item_id, ingredient_id)
    DO UPDATE SET quantity_needed = EXCLUDED.quantity_needed, notes = EXCLUDED.notes;

    IF v_existed THEN v_recipes_updated := v_recipes_updated + 1;
    ELSE v_recipes_created := v_recipes_created + 1;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'recipes_created', v_recipes_created,
    'recipes_updated', v_recipes_updated,
    'ingredients_created', v_ingredients_created
  );
END;
$function$;

REVOKE ALL ON FUNCTION public.import_recipes_tx(uuid, jsonb) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.import_recipes_tx(uuid, jsonb) TO authenticated, service_role;

