-- 4. RPC transfert atomique: paire transfer_out (source) / transfer_in (destination).
--    SECURITY DEFINER + assert_tenant_member + verrou source FOR UPDATE (anti double-clic).
CREATE OR REPLACE FUNCTION public.transfer_stock_between_venues(
  p_tenant_id uuid, p_ingredient_id uuid,
  p_from_venue_id uuid, p_to_venue_id uuid,
  p_quantity numeric, p_notes text DEFAULT NULL, p_created_by uuid DEFAULT NULL
) RETURNS uuid
LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $fn$
DECLARE v_from_stock NUMERIC(10,3); v_dest_id UUID; v_transfer_id UUID;
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  IF p_quantity IS NULL OR p_quantity <= 0 THEN
    RAISE EXCEPTION 'INVALID_QUANTITY' USING ERRCODE = '22023'; END IF;
  IF p_from_venue_id = p_to_venue_id THEN
    RAISE EXCEPTION 'SAME_VENUE' USING ERRCODE = '22023'; END IF;
  -- Les deux venues doivent appartenir au tenant.
  IF (SELECT count(*) FROM public.venues v
      WHERE v.id IN (p_from_venue_id, p_to_venue_id) AND v.tenant_id = p_tenant_id) <> 2 THEN
    RAISE EXCEPTION 'INVALID_VENUE' USING ERRCODE = '22023'; END IF;

  -- Verrou + controle de solde sur la ligne ingredient de la venue source.
  SELECT current_stock INTO v_from_stock FROM public.ingredients
  WHERE tenant_id = p_tenant_id AND id = p_ingredient_id AND venue_id IS NOT DISTINCT FROM p_from_venue_id
  FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'INGREDIENT_NOT_FOUND' USING ERRCODE = 'P0002'; END IF;
  IF v_from_stock < p_quantity THEN RAISE EXCEPTION 'INSUFFICIENT_STOCK' USING ERRCODE = '22023'; END IF;

  -- Ligne ingredient miroir cote destination (creee a la volee si absente).
  SELECT id INTO v_dest_id FROM public.ingredients
  WHERE tenant_id = p_tenant_id AND venue_id IS NOT DISTINCT FROM p_to_venue_id
    AND name = (SELECT name FROM public.ingredients WHERE id = p_ingredient_id);
  IF v_dest_id IS NULL THEN
    INSERT INTO public.ingredients (tenant_id, venue_id, name, unit, current_stock, min_stock_alert, cost_per_unit, category)
    SELECT tenant_id, p_to_venue_id, name, unit, 0, min_stock_alert, cost_per_unit, category
    FROM public.ingredients WHERE id = p_ingredient_id RETURNING id INTO v_dest_id;
  END IF;

  INSERT INTO public.stock_transfers (tenant_id, from_venue_id, to_venue_id, created_by, notes)
  VALUES (p_tenant_id, p_from_venue_id, p_to_venue_id, p_created_by, p_notes) RETURNING id INTO v_transfer_id;

  UPDATE public.ingredients SET current_stock = current_stock - p_quantity, updated_at = now() WHERE id = p_ingredient_id;
  UPDATE public.ingredients SET current_stock = current_stock + p_quantity, updated_at = now() WHERE id = v_dest_id;

  INSERT INTO public.stock_movements (tenant_id, ingredient_id, venue_id, movement_type, quantity, reference_id, notes, created_by)
  VALUES (p_tenant_id, p_ingredient_id, p_from_venue_id, 'transfer_out', -p_quantity, v_transfer_id, p_notes, p_created_by),
         (p_tenant_id, v_dest_id,      p_to_venue_id,   'transfer_in',   p_quantity, v_transfer_id, p_notes, p_created_by);
  RETURN v_transfer_id;
END; $fn$;
REVOKE ALL ON FUNCTION public.transfer_stock_between_venues(uuid,uuid,uuid,uuid,numeric,text,uuid) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.transfer_stock_between_venues(uuid,uuid,uuid,uuid,numeric,text,uuid) TO authenticated, service_role;

-- 5. Vue consolidee multi-venues (agregat + detail par venue).
CREATE OR REPLACE FUNCTION public.get_stock_status_by_venue(p_tenant_id uuid)
RETURNS TABLE (venue_id uuid, venue_name text, ingredient_name text, unit text,
               current_stock numeric, min_stock_alert numeric, is_low boolean)
LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $fn$
BEGIN
  PERFORM public.assert_tenant_member(p_tenant_id);
  RETURN QUERY
  SELECT i.venue_id, v.name, i.name, i.unit, i.current_stock, i.min_stock_alert,
         (i.current_stock <= i.min_stock_alert AND i.min_stock_alert > 0)
  FROM public.ingredients i
  LEFT JOIN public.venues v ON v.id = i.venue_id AND v.tenant_id = p_tenant_id
  WHERE i.tenant_id = p_tenant_id AND i.is_active = true
  ORDER BY v.name NULLS FIRST, i.name;
END; $fn$;
REVOKE ALL ON FUNCTION public.get_stock_status_by_venue(uuid) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.get_stock_status_by_venue(uuid) TO authenticated, service_role;
